function interpolate(x, x1, y1, x2, y2) {
  return y1 + ((x - x1) * (y2 - y1)) / (x2 - x1);
}

function lookupWFactor({ materialAlias, designTempC, seamType, serviceCondition, isElevatedTemp, heatTreatment, isAutogenousSolutionAnnealed, tcrC }, wLibrary) {
  const warnings = [];

  if (["occasional", "wind", "earthquake", "permissible_variation", "test", "displacement_stress"].includes(serviceCondition)) {
    return { W: 1.0, reason: "W is not required for this service condition; use 1.0.", warnings };
  }

  const seam = String(seamType || "unknown").toLowerCase();
  const hasLongitudinalOrSpiralWeld = ["erw", "efw", "saw", "lsaw", "hsaw", "spiral", "helical", "longitudinal", "welded"].includes(seam);

  if (!hasLongitudinalOrSpiralWeld) {
    return { W: 1.0, reason: "No longitudinal or spiral welded seam identified.", warnings };
  }

  if (isElevatedTemp === false) {
    return { W: 1.0, reason: "Not elevated-temperature fluid service.", warnings };
  }

  const groupId = resolveWGroupId(materialAlias, heatTreatment, isAutogenousSolutionAnnealed, wLibrary);
  if (!groupId) throw new Error("Cannot resolve W factor group from material alias.");

  const row = wLibrary.w_factor_table.find(r => r.id === groupId);
  if (!row) throw new Error("W factor row not found: " + groupId);

  if (row.id === "other_materials_formula") {
    if (tcrC == null) throw new Error("Tcr is required for other-materials W factor formula.");
    if (designTempC <= tcrC) return { W: 1.0, reason: "Ti <= Tcr", warnings };
    if (designTempC <= 816) return { W: 1 - 0.00164 * (designTempC - tcrC), reason: "Note 9 formula", warnings };
    throw new Error("Temperature above formula range; designer responsibility.");
  }

  const temps = row.temperature_values_degC;
  const values = row.w_values;

  // Below first numeric table point, use W = 1.0 where W is required.
  const firstIdx = values.findIndex(v => typeof v === "number");
  if (firstIdx < 0) throw new Error("No numeric W values in row.");
  if (designTempC <= temps[firstIdx]) {
    return { W: 1.0, reason: "Temperature at/below first applicable tabulated point.", warnings };
  }

  for (let i = firstIdx; i < temps.length - 1; i++) {
    const v1 = values[i];
    const v2 = values[i + 1];
    if (typeof v1 !== "number" || typeof v2 !== "number") continue;
    if (designTempC === temps[i]) return { W: v1, reason: "Exact table match", warnings };
    if (designTempC > temps[i] && designTempC <= temps[i + 1]) {
      return { W: interpolate(designTempC, temps[i], v1, temps[i + 1], v2), reason: "Linear interpolation", warnings };
    }
  }

  const exactIdx = temps.findIndex(t => t === designTempC);
  if (exactIdx >= 0 && typeof values[exactIdx] === "number") {
    return { W: values[exactIdx], reason: "Exact table match", warnings };
  }

  throw new Error("Design temperature outside applicable W factor range; designer review required.");
}
